const query = $input.first().json.query || {};
const q = (query.q || query.name || '').trim();

if (!q || q.length < 1) {
  return [{ json: { skip: true, q: q } }];
}

return [{ json: { q: q, normalized: q.toLowerCase().trim(), skip: false } }];

const items = $input.all();
const q = $('Validate Input').first().json.normalized;
const LIMIT = 15;

function normalize(s) {
  return String(s || '').toLowerCase().trim();
}

// Score: 0 = starts with, 1 = word starts with, 2 = contains
const matches = [];
for (const item of items) {
  const row = item.json || {};
  const name = row.name || '';
  if (!name) continue;
  const norm = normalize(name);
  let score = -1;
  if (norm.startsWith(q)) score = 0;
  else if (norm.split(/\s+/).some(w => w.startsWith(q))) score = 1;
  else if (norm.includes(q)) score = 2;
  if (score === -1) continue;
  matches.push({
    name: String(name).trim(),
    phone: String(row.phone || '').trim(),
    score: score
  });
}

matches.sort((a, b) => {
  if (a.score !== b.score) return a.score - b.score;
  return a.name.localeCompare(b.name, 'bg');
});

const limited = matches.slice(0, LIMIT).map(m => ({ name: m.name, phone: m.phone }));

return [{
  json: {
    success: true,
    q: $('Validate Input').first().json.q,
    count: limited.length,
    total: matches.length,
    patients: limited
  }
}];
